mapper.update:
UPDATE inventory SET quantity = quantity - #{qty}, version = version + 1
WHERE product_id = #{productId} AND warehouse_id = #{warehouseId}
  AND location_id = #{locationId} AND quantity >= #{qty}

mapper.select:
SELECT iv.id, iv.product_id, iv.warehouse_id, iv.location_id, iv.quantity, iv.version, p.product_name, p.product_code, p.cost_price, p.min_stock, p.max_stock, wh.warehouse_name, sl.location_name FROM inventory iv JOIN product p ON iv.product_id = p.id JOIN warehouse wh ON iv.warehouse_id = wh.id JOIN storage_location sl ON iv.location_id = sl.id
AND p.product_name LIKE CONCAT('%',#{productName},'%')
AND iv.warehouse_id = #{warehouseId}
ORDER BY iv.id LIMIT #{offset}, #{limit}

SELECT COUNT(*) FROM inventory iv JOIN product p ON iv.product_id = p.id


        AND p.product_name LIKE CONCAT('%',#{productName},'%')


        AND iv.warehouse_id = #{warehouseId}
